SELECT /* base.ec.pd :: PdhProdSkuPriceHist :: selectList */ h.* , ste.site_nm AS site_nm , prd.prod_nm AS prod_nm FROM pdh_prod_sku_price_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN pd_prod prd ON prd.prod_id = h.prod_id
ORDER BY h.hist_id ASC ORDER BY h.hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.pd :: PdhProdSkuPriceHist :: selectPageList */ h.* , ste.site_nm AS site_nm , prd.prod_nm AS prod_nm FROM pdh_prod_sku_price_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN pd_prod prd ON prd.prod_id = h.prod_id
ORDER BY h.hist_id ASC ORDER BY h.hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{limit} OFFSET #{offset}
